/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */
const todayKey = () => {
  const d = new Date();
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
};
const startOfDay = (d) => new Date(d.getFullYear(), d.getMonth(), d.getDate()).getTime();
const dayNumberFrom = (startISO) => {
  if (!startISO) return 1;
  const diff = startOfDay(new Date()) - startOfDay(new Date(startISO));
  return Math.max(1, Math.floor(diff / 86400000) + 1);
};
const keyOf = (d) => `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
const addDays = (key, n) => {
  const [Y, M, D] = key.split("-").map(Number);
  const d = new Date(Y, M - 1, D);
  d.setDate(d.getDate() + n);
  return keyOf(d);
};
const dayLabelOf = (key) => {
  const tk = todayKey();
  if (key === tk) return "Today";
  if (key === addDays(tk, -1)) return "Yesterday";
  const [Y, M, D] = key.split("-").map(Number);
  return new Date(Y, M - 1, D).toLocaleDateString("en-GB", { weekday: "short", day: "numeric", month: "short" });
};
const dayNumberForKey = (startISO, key) => {
  if (!startISO) return 1;
  const [Y, M, D] = key.split("-").map(Number);
  const diff = startOfDay(new Date(Y, M - 1, D)) - startOfDay(new Date(startISO));
  return Math.max(1, Math.floor(diff / 86400000) + 1);
};
const offsetToKey = (off) => addDays(todayKey(), -Math.abs(Math.round(Number(off) || 0)));

function buildPlan({ weightKg, heightCm, age, workouts, goal = "maintain" }) {
  const bmr = 10 * weightKg + 6.25 * heightCm - 5 * age - 78;
  const factor = workouts <= 0 ? 1.2 : workouts <= 2 ? 1.375 : workouts <= 4 ? 1.55 : workouts <= 6 ? 1.725 : 1.9;
  const tdee = bmr * factor;
  const maintenance = Math.min(5000, Math.max(1000, Math.round(tdee / 10) * 10));
  let target = tdee;
  if (goal === "lose") target = tdee - Math.min(500, Math.round(tdee * 0.2));      // gentle deficit, capped
  else if (goal === "gain") target = tdee + Math.min(350, Math.round(tdee * 0.12)); // gentle surplus, capped
  if (goal === "lose") target = Math.max(target, 1200, Math.round(bmr));            // never below resting needs
  const calories = Math.min(5000, Math.max(1000, Math.round(target / 10) * 10));
  const protein = Math.round((weightKg * (goal === "lose" ? 1.8 : 1.6)) / 5) * 5;   // hold more protein when cutting
  const fats = Math.round((calories * 0.28) / 9);
  const carbs = Math.max(0, Math.round((calories - protein * 4 - fats * 9) / 4));
  const burn = workouts <= 0 ? 0 : 250 + Math.min(150, workouts * 20);
  const wbump = Math.max(250, Math.round(burn / 10) * 10);   // workout days start higher to fuel training
  return { calories, workoutCalories: calories + wbump, protein, carbs, fats, workoutBurnPerSession: Math.round(burn / 10) * 10, goal, maintenance };
}

async function callClaude(messages, system, tools) {
  const body = { model: "claude-sonnet-4-6", max_tokens: 1000, messages };
  if (system) body.system = system;
  if (tools) body.tools = tools;
  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  const data = await res.json();
  return (data.content || []).filter((b) => b.type === "text").map((b) => b.text).join("\n");
}
function extractJSON(text) {
  if (!text) return null;
  const f = text.replace(/```json|```/g, "");
  const s = f.indexOf("{"), e = f.lastIndexOf("}");
  if (s === -1 || e === -1) return null;
  try { return JSON.parse(f.slice(s, e + 1)); } catch (x) { return null; }
}
async function callClaudeWeb(prompt) {
  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model: "claude-sonnet-4-6", max_tokens: 1000,
      messages: [{ role: "user", content: prompt }],
      tools: [{ type: "web_search_20250305", name: "web_search" }],
    }),
  });
  const data = await res.json();
  return (data.content || []).filter((b) => b.type === "text").map((b) => b.text).join("\n");
}

