const guessSlot = () => {
  const h = new Date().getHours();
  return h < 11 ? "breakfast" : h < 16 ? "lunch" : h < 21 ? "dinner" : "snack";
};
const fuelState = (pct) =>
  pct < 0.5 ? { word: "Light so far", note: "lots of room whenever you're hungry" }
  : pct < 0.85 ? { word: "Nicely fuelled", note: "a comfortable place to be" }
  : pct <= 1.05 ? { word: "Well fuelled", note: "right around your usual" }
  : { word: "Fully fuelled", note: "a fuller day, and that's completely fine" };
const macroState = (pct) => (pct < 0.6 ? "building" : pct <= 1.05 ? "on track" : "topped up");

