function renderInline(s, base) {
  return s.split(/(\*\*[^*]+\*\*)/g).map((p, i) =>
    /^\*\*[^*]+\*\*$/.test(p)
      ? <strong key={base + i}>{p.slice(2, -2)}</strong>
      : <span key={base + i}>{p}</span>
  );
}
function FormattedText({ text }) {
  const lines = (text || "").split("\n");
  return (
    <div>
      {lines.map((raw, i) => {
        const line = raw.trim();
        if (line === "") return <div key={"s" + i} style={{ height: 5 }} />;
        if (/^[-–*•]\s+/.test(line)) {
          return (
            <div key={"b" + i} style={{ display: "flex", gap: 8, margin: "2px 0", lineHeight: 1.45 }}>
              <span style={{ color: C.clay }}>•</span>
              <span style={{ flex: 1 }}>{renderInline(line.replace(/^[-–*•]\s+/, ""), "b" + i)}</span>
            </div>
          );
        }
        return <div key={"p" + i} style={{ margin: "2px 0", lineHeight: 1.5 }}>{renderInline(line, "p" + i)}</div>;
      })}
    </div>
  );
}
