function CoachView({ eaten, meals, dayType, todayTarget, dayMacros, gentle, onLog, onLogWorkout, onEdit, seed, clearSeed, dateNav }) {
  const [msgs, setMsgs] = useState([{ role: "assistant", text: "Hi, I'm Sage, your AI meal coach. The fastest way to log is to just show me a photo, no typing needed. Here's everything I can do:\n\n- **Snap your plate.** Send a photo of your meal and I'll estimate the calories and protein, list what I spotted, and drop an Add button so one tap logs it.\n- **Snap your fridge or counter.** Share a picture of what you've got and I'll put together a healthy meal that fits your day and hits your protein.\n- **Eating out or takeaway?** Just name it, like \"a chicken slider from Dave's Hot Chicken,\" and I'll look up the real menu numbers.\n- **Prefer to type?** That works too: \"chicken, rice, broccoli,\" or tweak on the fly with \"change my lunch to 400.\"\n- **Forgot a day?** Tell me what you had, even a few days back, and I'll log it to the right day.\n- **Did a workout?** Mention it and I'll estimate the burn and add it too.\n\nSo, what are you having? Snapping a photo is the quickest start.", meal: null }]);
  const [input, setInput] = useState("");
  const [pendingImg, setPendingImg] = useState(null);
  const [busy, setBusy] = useState(false);
  const scrollRef = useRef(null);
  const fileRef = useRef(null);
  const sentSeed = useRef(false);
  useEffect(() => { scrollRef.current?.scrollTo({ top: 9e9, behavior: "smooth" }); }, [msgs, busy]);

  const system = `You are Sage, the AI meal coach inside a gentle nutrition app. Your job is to help the user decide what to eat and give realistic calorie and protein estimates so they can log easily. You are warm, witty and easy going, like a clued up friend who loves food. Keep replies short and friendly with a light touch of humour (British spellings, no em dashes, no emojis). Never push restriction or guilt, food is to be enjoyed, and you keep things relaxed even when someone is over for the day. Only mention your name if asked.

What you help with:
- Cook from what they have: if the user lists or photographs the ingredients in their fridge and cupboards, suggest a single realistic meal built around what is actually there, sized to fit the room left in their day and to help them hit their protein.
- Eating out and takeaway: if they name a restaurant, cafe, takeaway, fast food chain, or a specific branded or shop bought item they ordered or plan to order, use web search for its real nutrition and base your estimate on that, mentioning briefly that you looked it up. For home cooked or generic foods, estimate from your own knowledge without searching.
- Logging, including past days: when they settle on something, or tell you what they already ate or cooked (even days ago), produce an estimate and offer to log it. This covers takeaway, dining out and home cooking. If it is a named place or product, search for the real numbers first.

Format every reply so it is easy to read at a glance, never one long block. Use real line breaks between parts:
- Open with a short, warm one liner.
- Put the meal name on its own line in **bold**.
- Give a quick one line method.
- List each component on its own line starting with "- ", like "- 2 eggs: ~160 kcal, 12g protein".
- Finish the breakdown with a bold total line like "**Total: ~380 kcal, 17g protein**".
- End with a short friendly question.

When the user shares a photo of their fridge, counter, or a meal, look at what is actually there and build your suggestion or estimate around it.

Today is a ${dayType} day, with roughly ${todayTarget} kcal of room and macro guides around protein ${dayMacros.protein}g, carbs ${dayMacros.carbs}g, fats ${dayMacros.fats}g. So far eaten: ${eaten.protein}g protein, ${eaten.carbs}g carbs, ${eaten.fats}g fats. Logged meals: ${meals.map((m) => m.name).join(", ") || "none"}.

When the user settles on a meal, append on its own final line exactly:
<<<ACTION>>>{"type":"meal","meal":{"name":"...","slot":"breakfast|lunch|dinner|snack","calories":0,"protein":0,"carbs":0,"fats":0}}<<<END>>>
If the user mentions a workout they did and want logged (e.g. "I ran 5k this morning"), append instead a workout action with a realistic calorie estimate:
<<<ACTION>>>{"type":"workout","workout":{"name":"...","calories":0,"duration":"e.g. 30 min"}}<<<END>>>
If they ask to edit a logged entry (e.g. "change my lunch to 400"), append instead:
<<<ACTION>>>{"type":"edit","edit":{"target":"lunch|breakfast|dinner|snack|last|<name>","field":"calories|protein|carbs|fats|name","value":400}}<<<END>>>
For a meal or workout, if the user refers to a past day, add a "dayOffset" number to that action's inner object where 0 is today, 1 is yesterday, 2 is two days ago, and so on (relative to today). Resolve phrases like "yesterday", "this morning" (0), "the day before yesterday" (2), or a weekday name to the matching number of days back. Omit dayOffset when they mean today.
Only one action block, only when relevant, and never mention it in your visible reply.`;

  const buildContent = (m) => {
    if (!m.image) return m.text;
    const comma = m.image.indexOf(",");
    const media = (m.image.slice(0, comma).match(/data:(.*?);/) || [])[1] || "image/jpeg";
    return [
      { type: "image", source: { type: "base64", media_type: media, data: m.image.slice(comma + 1) } },
      { type: "text", text: m.text || "Here is what I'm looking at." },
    ];
  };

  const run = async (text, image) => {
    const next = [...msgs, { role: "user", text, image: image || null }];
    setMsgs(next); setInput(""); setPendingImg(null); setBusy(true);
    try {
      const history = next.map((m) => ({ role: m.role, content: buildContent(m) }));
      const raw = await callClaude(history, system, [{ type: "web_search_20250305", name: "web_search" }]);
      let visible = raw, action = null;
      const mm = raw.match(/<<<ACTION>>>([\s\S]*?)<<<END>>>/);
      if (mm) { visible = raw.replace(/<<<ACTION>>>[\s\S]*?<<<END>>>/, "").trim(); action = extractJSON(mm[1]); }
      if (action && action.type === "edit") {
        const ok = onEdit(action.edit);
        setMsgs((p) => [...p, { role: "assistant", text: visible || (ok ? "Done, updated that for you." : "I couldn't find that one to change."), meal: null }]);
      } else if (action && action.type === "workout" && action.workout) {
        setMsgs((p) => [...p, { role: "assistant", text: visible, meal: null, workout: action.workout }]);
      } else {
        setMsgs((p) => [...p, { role: "assistant", text: visible, meal: action && action.type === "meal" ? action.meal : null }]);
      }
    } catch (e) {
      setMsgs((p) => [...p, { role: "assistant", text: "I couldn't reach the kitchen just now. The AI features run inside the Claude artifact preview, so make sure you're there and try once more.", meal: null }]);
    }
    setBusy(false);
  };
  const send = () => { if (busy) return; const t = input.trim(); if (t || pendingImg) run(t, pendingImg); };
  const onFile = (e) => {
    const f = e.target.files?.[0]; e.target.value = ""; if (!f) return;
    const r = new FileReader(); r.onload = () => setPendingImg(r.result); r.readAsDataURL(f);
  };
  useEffect(() => {
    if (seed && !sentSeed.current) { sentSeed.current = true; run(seed); clearSeed(); }
    // eslint-disable-next-line
  }, [seed]);

  const lastAi = [...msgs].reverse().find((m) => m.role === "assistant");
  const mood = busy ? "thinking" : lastAi && (lastAi.meal || lastAi.workout) ? "happy" : "idle";

  return (
    <div className="cc-enter">
      <div style={{ display: "flex", alignItems: "center", gap: 13, marginBottom: 14, paddingTop: 6 }}>
        <CoachAvatar mood={mood} size={62} />
        <div>
          <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
            <h2 className="cc-display" style={{ fontSize: 22, fontWeight: 600, letterSpacing: "-0.01em" }}>Sage</h2>
            <span style={{ fontSize: 10.5, fontWeight: 700, letterSpacing: "0.09em", textTransform: "uppercase", color: C.clayDeep, background: `${C.clay}1f`, border: `1px solid ${C.clay}3a`, borderRadius: 999, padding: "3px 9px" }}>AI coach</span>
          </div>
          <p className="cc-soft" style={{ fontSize: 13 }}>Snap a photo or just tell me what you ate, and I'll estimate it</p>
        </div>
      </div>
      <DatePill nav={dateNav} hint />
      <div className="cc-card cc-scroll" ref={scrollRef} style={{ padding: 16, height: "min(56vh, 460px)", overflowY: "auto", display: "flex", flexDirection: "column", gap: 12, marginBottom: 12 }}>
        {msgs.map((m, i) => (
          <div key={i} style={{ display: "flex", flexDirection: "column", alignItems: m.role === "user" ? "flex-end" : "flex-start", gap: 8 }}>
            {m.image && <img src={m.image} alt="shared" style={{ maxWidth: "70%", borderRadius: 16, border: "1px solid rgba(255,255,255,0.7)" }} />}
            {m.text && <div className={`cc-bubble ${m.role === "user" ? "me" : "ai"}`}>{m.role === "assistant" ? <FormattedText text={m.text} /> : m.text}</div>}
            {m.meal && (() => {
              const dk = m.meal.dayOffset != null ? offsetToKey(m.meal.dayOffset) : undefined;
              const suffix = dk && dk !== todayKey() ? ` to ${dayLabelOf(dk)}` : "";
              return (
                <button className="cc-btn cc-pop" onClick={() => onLog(m.meal, dk)} style={{ background: `linear-gradient(135deg,${C.clay},${C.clayDeep})`, color: "#fff", padding: "11px 16px", fontSize: 13.5, fontWeight: 700, display: "inline-flex", alignItems: "center", gap: 8, boxShadow: "0 10px 24px rgba(194,114,78,0.3)" }}>
                  <Plus size={16} /> Add {m.meal.name}{gentle ? "" : ` · ${m.meal.calories} kcal`}{suffix}
                </button>
              );
            })()}
            {m.workout && (() => {
              const dk = m.workout.dayOffset != null ? offsetToKey(m.workout.dayOffset) : undefined;
              const suffix = dk && dk !== todayKey() ? ` to ${dayLabelOf(dk)}` : "";
              return (
                <button className="cc-btn cc-pop" onClick={() => onLogWorkout(m.workout, dk)} style={{ background: `linear-gradient(135deg,${C.coral},${C.clayDeep})`, color: "#fff", padding: "11px 16px", fontSize: 13.5, fontWeight: 700, display: "inline-flex", alignItems: "center", gap: 8, boxShadow: "0 10px 24px rgba(194,114,78,0.3)" }}>
                  <Dumbbell size={16} /> Add {m.workout.name}{gentle ? "" : ` · ${m.workout.calories} kcal`}{suffix}
                </button>
              );
            })()}
          </div>
        ))}
        {busy && <div className="cc-bubble ai" style={{ display: "inline-flex", alignItems: "center", gap: 8 }}><Loader2 className="cc-spin" size={15} /> thinking</div>}
      </div>
      {pendingImg && (
        <div className="cc-pop" style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 9, padding: 8, borderRadius: 14, background: "rgba(255,255,255,0.6)", border: "1px solid rgba(255,255,255,0.75)", width: "fit-content" }}>
          <img src={pendingImg} alt="attached" style={{ width: 40, height: 40, borderRadius: 10, objectFit: "cover" }} />
          <span className="cc-soft" style={{ fontSize: 12.5 }}>Photo attached</span>
          <button className="cc-btn" onClick={() => setPendingImg(null)} style={{ background: "transparent", padding: 4, display: "flex" }}><X size={15} color={C.muted} /></button>
        </div>
      )}
      <input ref={fileRef} type="file" accept="image/*" capture="environment" onChange={onFile} />
      <div style={{ display: "flex", gap: 9 }}>
        <button className="cc-btn cc-ghost" onClick={() => fileRef.current?.click()} disabled={busy} style={{ padding: "0 14px", display: "flex", alignItems: "center" }} title="Add a photo"><Camera size={18} color={C.clay} /></button>
        <input className="cc-input" placeholder={pendingImg ? "Add a note, or just send" : 'e.g. "chicken, rice, broccoli" or "Pret tuna baguette"'} value={input} onChange={(e) => setInput(e.target.value)} onKeyDown={(e) => e.key === "Enter" && send()} />
        <button className="cc-btn cc-primary" onClick={send} disabled={busy} style={{ padding: "0 18px", display: "flex", alignItems: "center" }}><Send size={18} /></button>
      </div>
    </div>
  );
}

