function SnapMeal({ onLog }) {
  const [preview, setPreview] = useState(null);
  const [busy, setBusy] = useState(false);
  const [result, setResult] = useState(null);
  const [err, setErr] = useState(null);
  const fileRef = useRef(null);
  const onFile = (e) => {
    const file = e.target.files?.[0]; e.target.value = ""; if (!file) return;
    setErr(null); setResult(null);
    const reader = new FileReader();
    reader.onload = async () => {
      const dataUrl = reader.result; setPreview(dataUrl);
      const b64 = dataUrl.split(",")[1]; setBusy(true);
      try {
        const raw = await callClaude([{ role: "user", content: [
          { type: "image", source: { type: "base64", media_type: file.type || "image/jpeg", data: b64 } },
          { type: "text", text: 'Estimate the food in this photo. Reply ONLY with JSON: {"name":"short dish name","items":["item 1"],"calories":0,"protein":0,"carbs":0,"fats":0,"confidence":"low|medium|high"}. Use realistic average portions.' },
        ] }]);
        const j = extractJSON(raw); if (!j) throw new Error("parse");
        setResult({ name: j.name || "Meal", items: j.items || [], calories: j.calories || 0, protein: j.protein || 0, carbs: j.carbs || 0, fats: j.fats || 0, confidence: j.confidence || "medium", extra: "" });
      } catch (e2) { setErr("Couldn't read that one. The AI vision runs inside the Claude artifact preview. You can still log it by hand below."); setResult({ name: "Meal", items: [], calories: 0, protein: 0, carbs: 0, fats: 0, confidence: "low", extra: "" }); }
      setBusy(false);
    };
    reader.readAsDataURL(file);
  };
  const upd = (k, v) => setResult((r) => ({ ...r, [k]: v }));
  return (
    <div>
      <input ref={fileRef} type="file" accept="image/*" capture="environment" onChange={onFile} />
      {!preview && (
        <button className="cc-card cc-btn" onClick={() => fileRef.current?.click()} style={{ width: "100%", padding: 40, display: "flex", flexDirection: "column", alignItems: "center", gap: 14 }}>
          <div style={{ width: 64, height: 64, borderRadius: 20, background: "rgba(203,138,160,0.18)", display: "flex", alignItems: "center", justifyContent: "center" }}><Camera size={28} color={C.protein} /></div>
          <div style={{ fontWeight: 600, fontSize: 16 }}>Take or choose a photo</div>
          <div className="cc-soft" style={{ fontSize: 13 }}>Just snap it and I'll do the rest, no typing needed</div>
        </button>
      )}
      {preview && (
        <div className="cc-card" style={{ padding: 16, marginBottom: 14 }}>
          <img src={preview} alt="meal" style={{ width: "100%", borderRadius: 18, maxHeight: 280, objectFit: "cover" }} />
          {busy && <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 10, padding: 20 }}><Loader2 className="cc-spin" size={20} color={C.protein} /><span className="cc-soft" style={{ fontSize: 14 }}>Reading your plate…</span></div>}
        </div>
      )}
      {err && <div className="cc-card" style={{ padding: 14, marginBottom: 14, fontSize: 13, color: C.clayDeep }}>{err}</div>}
      {result && !busy && (
        <div className="cc-card cc-pop" style={{ padding: 18 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
            <span className="cc-tag cc-soft">Confirm and adjust</span>
            <span style={{ fontSize: 11, fontWeight: 700, padding: "4px 10px", borderRadius: 999, textTransform: "capitalize", background: `${C.sage}22`, color: C.sage }}>{result.confidence} confidence</span>
          </div>
          <label className="cc-soft" style={{ fontSize: 12, fontWeight: 600 }}>Dish</label>
          <input className="cc-input" value={result.name} onChange={(e) => upd("name", e.target.value)} style={{ margin: "6px 0 12px" }} />
          {result.items.length > 0 && (
            <div style={{ marginBottom: 12 }}>
              <div className="cc-soft" style={{ fontSize: 12, fontWeight: 600, marginBottom: 6 }}>Spotted</div>
              <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>{result.items.map((it, i) => (<span key={i} style={{ fontSize: 12.5, padding: "5px 11px", borderRadius: 999, background: "rgba(255,255,255,0.6)", border: `1px solid ${C.line}` }}>{it}</span>))}</div>
            </div>
          )}
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 8, marginBottom: 12 }}>
            {[["calories", "Cals", C.clay], ["protein", "Prot", C.protein], ["carbs", "Carbs", C.carbs], ["fats", "Fats", C.fats]].map(([f, lab, c]) => (
              <div key={f} style={{ textAlign: "center" }}>
                <div style={{ fontSize: 10.5, marginBottom: 4, textTransform: "uppercase", color: c, fontWeight: 700 }}>{lab}</div>
                <input className="cc-input" inputMode="numeric" value={result[f]} onChange={(e) => upd(f, e.target.value)} style={{ padding: "9px 4px", textAlign: "center", fontWeight: 600 }} />
              </div>
            ))}
          </div>
          <label className="cc-soft" style={{ fontSize: 12, fontWeight: 600 }}>Add anything not in the picture</label>
          <input className="cc-input" placeholder="e.g. a flat white" value={result.extra} onChange={(e) => upd("extra", e.target.value)} style={{ margin: "6px 0 14px" }} />
          <button className="cc-btn cc-primary" onClick={() => { const name = result.extra ? `${result.name} + ${result.extra}` : result.name; onLog({ name, calories: result.calories, protein: result.protein, carbs: result.carbs, fats: result.fats }); setPreview(null); setResult(null); }} style={{ width: "100%", padding: 14, fontSize: 15, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}><Plus size={18} /> Add this meal</button>
          <button className="cc-btn cc-ghost" onClick={() => { setPreview(null); setResult(null); setErr(null); }} style={{ width: "100%", padding: 11, fontSize: 13, marginTop: 9 }}>Retake</button>
        </div>
      )}
    </div>
  );
}

