/*  Move (workout from screenshot)                                     */
/* ================================================================== */
function SnapWorkout({ onLog, dateNav }) {
  const [preview, setPreview] = useState(null);
  const [busy, setBusy] = useState(false);
  const [rows, setRows] = useState(null);
  const [err, setErr] = useState(null);
  const [text, setText] = useState("");
  const fileRef = useRef(null);
  const onFile = (e) => {
    const file = e.target.files?.[0]; e.target.value = ""; if (!file) return;
    setErr(null); setRows(null);
    const reader = new FileReader();
    reader.onload = async () => {
      const dataUrl = reader.result; setPreview(dataUrl);
      const b64 = dataUrl.split(",")[1]; setBusy(true);
      try {
        const raw = await callClaude([{ role: "user", content: [
          { type: "image", source: { type: "base64", media_type: file.type || "image/jpeg", data: b64 } },
          { type: "text", text: `This is a screenshot from a fitness or activity app. Today's date is ${todayKey()}. It may show a list of individual workouts (each with a name, time and calories), OR a daily activity summary with rings such as Apple Fitness (a Move ring showing active energy in calories like "472/300 CAL", an Exercise ring in minutes, a Stand ring). Note the date shown near the top of the screen, e.g. "Friday, Jun 26, 2026". If individual workouts are listed, return one entry for each. If it is an activity summary, return a single entry named "Daily activity" using the Move active energy as the calories (use the Move number such as 472, NOT the total calories, which include resting energy) and the Exercise minutes as the duration. For every entry include "date" as the day the activity is from in YYYY-MM-DD format, converting the date shown in the screenshot; if no date is visible, use today's date ${todayKey()}. Reply ONLY with JSON, no prose: {"workouts":[{"name":"...","duration":"e.g. 32 min","calories":0,"effort":"a short phrase on how active the day or session was","date":"YYYY-MM-DD"}]}.` },
        ] }]);
        const j = extractJSON(raw); if (!j || !Array.isArray(j.workouts) || j.workouts.length === 0) throw new Error("parse");
        setRows(j.workouts.map((w) => ({ name: w.name || "Workout", duration: w.duration || "", calories: w.calories || 0, effort: w.effort || "", date: (typeof w.date === "string" && /^\d{4}-\d{2}-\d{2}$/.test(w.date) && w.date <= todayKey()) ? w.date : "" })));
      } catch (e2) { setErr("Couldn't read that screenshot. The AI vision runs inside the Claude artifact preview. You can add it by hand below."); setRows([{ name: "Workout", duration: "", calories: 0 }]); }
      setBusy(false);
    };
    reader.readAsDataURL(file);
  };
  const estimateText = async () => {
    const t = text.trim(); if (!t || busy) return;
    setErr(null); setRows(null); setBusy(true);
    try {
      const raw = await callClaude([{ role: "user", content: [{ type: "text", text: `A user logged this workout or gym session today: "${t}". Estimate it for an average adult. Reply ONLY with JSON, no prose: {"workouts":[{"name":"short name","duration":"e.g. 35 min","calories":0,"effort":"a short phrase on how effective or intense it was, e.g. 'solid strength session' or 'easy zone 2'"}]}. One entry per distinct activity, realistic calorie burns, keep names short.` }] }]);
      const j = extractJSON(raw); if (!j || !Array.isArray(j.workouts) || j.workouts.length === 0) throw new Error("parse");
      setRows(j.workouts.map((w) => ({ name: w.name || "Workout", duration: w.duration || "", calories: w.calories || 0, effort: w.effort || "" })));
    } catch (e2) {
      setErr("Couldn't estimate that just now. The AI runs inside the Claude artifact preview. You can still add it by hand below.");
      setRows([{ name: t, duration: "", calories: 0, effort: "" }]);
    }
    setBusy(false);
  };
  const updRow = (i, k, v) => setRows((r) => r.map((row, idx) => (idx === i ? { ...row, [k]: v } : row)));
  const addRow = () => setRows((r) => [...r, { name: "Workout", duration: "", calories: 0, effort: "", date: r[0]?.date || "" }]);
  return (
    <div className="cc-enter">
      <SectionHead Icon={Dumbbell} c={C.coral} title="Log a workout" sub="Snap your fitness app or list your session, and I'll estimate the burn" />
      <DatePill nav={dateNav} hint />
      <input ref={fileRef} type="file" accept="image/*" onChange={onFile} />
      {!preview && !rows && (
        <>
          <button className="cc-card cc-btn" onClick={() => fileRef.current?.click()} style={{ width: "100%", padding: 32, display: "flex", flexDirection: "column", alignItems: "center", gap: 12, marginBottom: 14 }}>
            <div style={{ width: 60, height: 60, borderRadius: 18, background: "rgba(222,145,112,0.18)", display: "flex", alignItems: "center", justifyContent: "center" }}><ImageIcon size={26} color={C.coral} /></div>
            <div style={{ fontWeight: 600, fontSize: 16 }}>Upload a fitness screenshot</div>
            <div className="cc-soft" style={{ fontSize: 13, textAlign: "center" }}>Apple Fitness, a watch summary, anything with the burn</div>
          </button>
          <div style={{ display: "flex", alignItems: "center", gap: 12, margin: "2px 0 14px" }}>
            <div style={{ flex: 1, height: 1, background: C.line }} />
            <span className="cc-muted" style={{ fontSize: 11.5, fontWeight: 600 }}>or list it</span>
            <div style={{ flex: 1, height: 1, background: C.line }} />
          </div>
          <div className="cc-card" style={{ padding: 16 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 9, marginBottom: 10 }}>
              <Dumbbell size={16} color={C.coral} />
              <span style={{ fontWeight: 700, fontSize: 14 }}>Type your workout</span>
            </div>
            <textarea className="cc-input" value={text} onChange={(e) => setText(e.target.value)} rows={3} placeholder="e.g. bench press 3x10, squats 4x8, 20 min treadmill" style={{ width: "100%", resize: "none", lineHeight: 1.5, marginBottom: 10 }} />
            <button className="cc-btn cc-primary" onClick={estimateText} disabled={busy || !text.trim()} style={{ width: "100%", padding: 13, fontSize: 14.5, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
              {busy ? <><Loader2 className="cc-spin" size={17} /> Estimating…</> : <><Sparkles size={16} /> Estimate the burn</>}
            </button>
            <p className="cc-muted" style={{ fontSize: 11, marginTop: 9, lineHeight: 1.45 }}>Sage reads your exercises and estimates the calories and how hard the session was.</p>
          </div>
        </>
      )}
      {preview && (
        <div className="cc-card" style={{ padding: 16, marginBottom: 14 }}>
          <img src={preview} alt="workout" style={{ width: "100%", borderRadius: 18, maxHeight: 320, objectFit: "contain", background: "rgba(255,255,255,0.4)" }} />
          {busy && <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 10, padding: 20 }}><Loader2 className="cc-spin" size={20} color={C.coral} /><span className="cc-soft" style={{ fontSize: 14 }}>Reading your session…</span></div>}
        </div>
      )}
      {err && <div className="cc-card" style={{ padding: 14, marginBottom: 14, fontSize: 13, color: C.clayDeep }}>{err}</div>}
      {rows && !busy && (
        <div className="cc-card cc-pop" style={{ padding: 18 }}>
          <span className="cc-tag cc-soft" style={{ display: "block", marginBottom: 12 }}>Confirm and adjust</span>
          {rows[0]?.date && rows[0].date !== todayKey() && (
            <div style={{ display: "flex", alignItems: "center", gap: 7, marginBottom: 12, padding: "9px 12px", borderRadius: 12, background: "rgba(213,138,102,0.14)", border: `1px solid ${C.clay}33` }}>
              <CalendarDays size={14} color={C.clay} />
              <span style={{ fontSize: 12.5, color: C.ink, fontWeight: 600 }}>Read from your screenshot, logging to {dayLabelOf(rows[0].date)}</span>
            </div>
          )}
          {rows.map((row, i) => (
            <div key={i} style={{ marginBottom: 12, paddingBottom: 12, borderBottom: i < rows.length - 1 ? `1px solid ${C.line}` : "none" }}>
              <input className="cc-input" value={row.name} onChange={(e) => updRow(i, "name", e.target.value)} style={{ marginBottom: row.effort ? 6 : 8 }} />
              {row.effort && <div className="cc-soft" style={{ fontSize: 12, margin: "0 0 8px 2px", display: "flex", alignItems: "center", gap: 6 }}><Sparkles size={12} color={C.coral} /> {row.effort}</div>}
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
                <div><div className="cc-muted" style={{ fontSize: 10.5, marginBottom: 4, textTransform: "uppercase" }}>Duration</div><input className="cc-input" value={row.duration} placeholder="32 min" onChange={(e) => updRow(i, "duration", e.target.value)} style={{ padding: "9px 10px" }} /></div>
                <div><div className="cc-muted" style={{ fontSize: 10.5, marginBottom: 4, textTransform: "uppercase", color: C.coral }}>Calories</div><input className="cc-input" inputMode="numeric" value={row.calories} onChange={(e) => updRow(i, "calories", e.target.value)} style={{ padding: "9px 10px", fontWeight: 600 }} /></div>
              </div>
            </div>
          ))}
          <button className="cc-btn cc-ghost" onClick={addRow} style={{ width: "100%", padding: 10, fontSize: 13, marginBottom: 12, display: "flex", alignItems: "center", justifyContent: "center", gap: 7 }}><Plus size={15} /> Add another</button>
          <button className="cc-btn cc-primary" onClick={() => { rows.forEach((r) => onLog(r, r.date || undefined)); setPreview(null); setRows(null); setText(""); }} style={{ width: "100%", padding: 14, fontSize: 15, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}><Check size={18} /> Add {rows.length > 1 ? `${rows.length} workouts` : "workout"}{rows[0]?.date && rows[0].date !== todayKey() ? ` to ${dayLabelOf(rows[0].date)}` : ""}</button>
          <button className="cc-btn cc-ghost" onClick={() => { setPreview(null); setRows(null); setErr(null); setText(""); }} style={{ width: "100%", padding: 11, fontSize: 13, marginTop: 9 }}>Start over</button>
        </div>
      )}
    </div>
  );
}

/* ================================================================== */
/*  Staples                                                            */
/* ================================================================== */
function Staples({ staples, setStaples, onQuick, dateNav }) {
  const slots = [
    { key: "meals", label: "Favourite Meals", c: C.clay, icon: Utensils },
    { key: "bars", label: "Protein Bars", c: C.protein, icon: Bookmark },
    { key: "powders", label: "Protein Powders", c: C.sage, icon: Sparkles },
  ];
  const [open, setOpen] = useState(null);
  const [draft, setDraft] = useState({ name: "", calories: "", protein: "" });
  const [snapping, setSnapping] = useState(false);
  const [snapErr, setSnapErr] = useState(null);
  const [snapPic, setSnapPic] = useState(null);
  const [looking, setLooking] = useState(false);
  const [lookNote, setLookNote] = useState(null);
  const fileRef = useRef(null);
  const resetForm = () => { setDraft({ name: "", calories: "", protein: "" }); setSnapErr(null); setSnapPic(null); setSnapping(false); setLooking(false); setLookNote(null); };
  const add = (key) => {
    if (!draft.name) return;
    const item = { id: Date.now() + Math.random(), name: draft.name, calories: Math.max(0, Math.round(Number(draft.calories) || 0)), protein: Math.max(0, Math.round(Number(draft.protein) || 0)) };
    setStaples((s) => ({ ...s, [key]: [...s[key], item] })); resetForm(); setOpen(null);
  };
  const remove = (key, id) => setStaples((s) => ({ ...s, [key]: s[key].filter((i) => i.id !== id) }));
  const analyse = (e, slotKey) => {
    const file = e.target.files?.[0]; e.target.value = ""; if (!file) return;
    setSnapErr(null);
    const reader = new FileReader();
    reader.onload = async () => {
      const dataUrl = reader.result; setSnapPic(dataUrl);
      const b64 = dataUrl.split(",")[1];
      const hint = slotKey === "powders" ? "a tub or scoop of protein powder (read the per-serving label if visible)" : slotKey === "bars" ? "a protein bar (read the wrapper label if visible)" : "a meal or food item";
      setSnapping(true);
      try {
        const raw = await callClaude([{ role: "user", content: [
          { type: "image", source: { type: "base64", media_type: file.type || "image/jpeg", data: b64 } },
          { type: "text", text: `This photo shows ${hint}. Give a realistic per serving estimate. Reply ONLY with JSON: {"name":"short name","calories":0,"protein":0}.` },
        ] }]);
        const j = extractJSON(raw); if (!j) throw new Error("parse");
        setDraft({ name: j.name || "", calories: String(j.calories ?? ""), protein: String(j.protein ?? "") });
      } catch (err) { setSnapErr("Couldn't read that one. The AI vision runs inside the Claude artifact preview. You can still type the numbers below."); }
      setSnapping(false);
    };
    reader.readAsDataURL(file);
  };
  const lookup = async (slotKey) => {
    const q = draft.name.trim(); if (!q || looking) return;
    setLooking(true); setLookNote(null);
    const kind = slotKey === "powders" ? "per scoop as directed on the label" : slotKey === "bars" ? "per bar" : "per typical serving";
    try {
      const raw = await callClaudeWeb(`Find the packaged food product "${q}". Search the web for its official nutrition facts. Give the figures ${kind}. Reply with ONLY a JSON object and nothing else: {"name":"full product name with flavour if known","calories":0,"protein":0,"found":true}. If you cannot find a real match, set "found" to false.`);
      const j = extractJSON(raw);
      if (j && j.found !== false && (Number(j.calories) || Number(j.protein))) {
        setDraft({ name: j.name || q, calories: String(j.calories ?? ""), protein: String(j.protein ?? "") });
        setLookNote({ ok: true, text: "Pulled from the web. Worth a quick check, then save." });
      } else {
        setLookNote({ ok: false, text: "Couldn't find a reliable match. Try the full brand and flavour, or type the numbers in." });
      }
    } catch (e) {
      setLookNote({ ok: false, text: "Couldn't search just now. The web lookup runs inside the Claude artifact preview." });
    }
    setLooking(false);
  };
  return (
    <div className="cc-enter">
      <SectionHead Icon={Bookmark} c={C.clay} title="My staples" sub="Save what you reach for often, add it in one tap" />
      <DatePill nav={dateNav} hint />
      {slots.map((slot) => (
        <div key={slot.key} className="cc-card" style={{ padding: 18, marginBottom: 16 }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 14 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
              <div style={{ width: 34, height: 34, borderRadius: 11, background: `${slot.c}22`, display: "flex", alignItems: "center", justifyContent: "center" }}><slot.icon size={17} color={slot.c} /></div>
              <span className="cc-display" style={{ fontWeight: 600, fontSize: 16 }}>{slot.label}</span>
            </div>
            <button className="cc-btn" onClick={() => { const willOpen = open !== slot.key; setOpen(willOpen ? slot.key : null); resetForm(); }} style={{ background: `${slot.c}22`, color: slot.c, padding: "7px 10px", display: "flex", alignItems: "center", gap: 5, fontSize: 12.5 }}><Plus size={15} /> Add</button>
          </div>
          {open === slot.key && (
            <div className="cc-pop" style={{ background: "rgba(255,255,255,0.5)", borderRadius: 16, padding: 14, marginBottom: 12, border: "1px solid rgba(255,255,255,0.7)" }}>
              <input ref={fileRef} type="file" accept="image/*" capture="environment" onChange={(e) => analyse(e, slot.key)} />
              <button className="cc-btn" onClick={() => fileRef.current?.click()} disabled={snapping} style={{ width: "100%", padding: 12, marginBottom: 12, display: "flex", alignItems: "center", justifyContent: "center", gap: 8, fontSize: 13.5, background: `${slot.c}1f`, color: slot.c, border: `1px solid ${slot.c}3a` }}>
                {snapping ? <><Loader2 className="cc-spin" size={16} /> Reading your photo…</> : <><Camera size={16} /> Snap to fill in the numbers</>}
              </button>
              {snapPic && !snapping && <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10 }}><img src={snapPic} alt="staple" style={{ width: 46, height: 46, borderRadius: 11, objectFit: "cover" }} /><span className="cc-soft" style={{ fontSize: 12.5 }}>Filled in from your photo. Tweak below.</span></div>}
              {snapErr && <div style={{ fontSize: 12.5, color: C.clayDeep, marginBottom: 10, lineHeight: 1.5 }}>{snapErr}</div>}
              <div style={{ display: "flex", alignItems: "center", gap: 10, margin: "2px 0 12px" }}><div style={{ flex: 1, height: 1, background: C.line }} /><span className="cc-muted" style={{ fontSize: 11 }}>or look it up by name</span><div style={{ flex: 1, height: 1, background: C.line }} /></div>
              <div style={{ display: "flex", gap: 8, marginBottom: 8 }}>
                <input className="cc-input" placeholder="e.g. Barebells caramel protein bar" value={draft.name} onChange={(e) => setDraft({ ...draft, name: e.target.value })} onKeyDown={(e) => e.key === "Enter" && lookup(slot.key)} style={{ flex: 1 }} />
                <button className="cc-btn" onClick={() => lookup(slot.key)} disabled={looking || !draft.name.trim()} title="Find nutrition online" style={{ background: `${slot.c}1f`, color: slot.c, border: `1px solid ${slot.c}3a`, padding: "0 15px", display: "flex", alignItems: "center", gap: 6, fontSize: 13 }}>
                  {looking ? <Loader2 className="cc-spin" size={16} /> : <Search size={16} />}
                </button>
              </div>
              {lookNote && <div style={{ fontSize: 12, marginBottom: 10, lineHeight: 1.5, color: lookNote.ok ? C.sage : C.clayDeep }}>{lookNote.text}</div>}
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginBottom: 10 }}>
                <input className="cc-input" inputMode="numeric" placeholder="Calories" value={draft.calories} onChange={(e) => setDraft({ ...draft, calories: e.target.value })} />
                <input className="cc-input" inputMode="numeric" placeholder="Protein (g)" value={draft.protein} onChange={(e) => setDraft({ ...draft, protein: e.target.value })} />
              </div>
              <button className="cc-btn cc-primary" onClick={() => add(slot.key)} style={{ width: "100%", padding: 11, fontSize: 13.5 }}>Save staple</button>
            </div>
          )}
          {staples[slot.key].length === 0 ? (
            <div style={{ border: `1px dashed ${C.line}`, borderRadius: 14, padding: 22, textAlign: "center" }}><p className="cc-muted" style={{ fontSize: 13 }}>Empty for now. Add a go-to and it gets a one tap button.</p></div>
          ) : (
            <div style={{ display: "grid", gap: 9 }}>
              {staples[slot.key].map((item) => (
                <div key={item.id} style={{ display: "flex", alignItems: "center", gap: 10, background: "rgba(255,255,255,0.5)", borderRadius: 13, padding: "11px 12px", border: `1px solid ${C.line}` }}>
                  <div style={{ flex: 1, minWidth: 0 }}><div style={{ fontWeight: 600, fontSize: 14 }}>{item.name}</div><div className="cc-soft" style={{ fontSize: 12 }}>{item.calories} kcal · {item.protein}g protein</div></div>
                  <button className="cc-btn" onClick={() => remove(slot.key, item.id)} style={{ background: "transparent", padding: 6 }}><X size={15} color={C.muted} /></button>
                  <button className="cc-btn" onClick={() => onQuick({ name: item.name, calories: item.calories, protein: item.protein, carbs: 0, fats: 0 })} style={{ background: slot.c, color: "#fff", width: 34, height: 34, borderRadius: 11, display: "flex", alignItems: "center", justifyContent: "center" }}><Plus size={18} strokeWidth={2.6} /></button>
                </div>
              ))}
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

/* ================================================================== */
/*  Insights  +  weekly recap                                          */
/* ================================================================== */
function Insights({ meals, workouts, streak, gentle, startDate }) {
  const [recap, setRecap] = useState(null);
  const [recapBusy, setRecapBusy] = useState(false);
  const [anchor, setAnchor] = useState(todayKey());

  const t = todayKey();
  const startK = startDate ? keyOf(new Date(startDate)) : null;
  const anchorToday = anchor === t;
  const insNav = {
    dayLabel: dayLabelOf(anchor), viewingToday: anchorToday,
    canBack: !startK || anchor > startK, canFwd: !anchorToday,
    onPrev: () => setAnchor((a) => { const p = addDays(a, -1); return startK && p < startK ? a : p; }),
    onNext: () => setAnchor((a) => { const n = addDays(a, 1); return n > t ? a : n; }),
    onToday: () => setAnchor(t), value: anchor, minKey: startK, maxKey: t, onPick: (k) => setAnchor(k),
  };

  const chart = [];
  const windowKeys = new Set();
  for (let i = 6; i >= 0; i--) {
    const k = addDays(anchor, -i);
    windowKeys.add(k);
    const [Y, M, D] = k.split("-").map(Number);
    const dd = new Date(Y, M - 1, D);
    chart.push({
      label: ["S", "M", "T", "W", "T", "F", "S"][dd.getDay()],
      n: meals.filter((m) => m.date === k).length,
      mv: workouts.filter((w) => w.date === k).length,
    });
  }
  const maxN = Math.max(1, ...chart.map((x) => x.n));
  const daysWithMeals = chart.filter((d) => d.n).length;
  const daysWithMove = chart.filter((d) => d.mv).length;

  const wMeals = meals.filter((m) => windowKeys.has(m.date));
  const wWorkouts = workouts.filter((w) => windowKeys.has(w.date));
  const daysTracked = new Set([...wMeals, ...wWorkouts].map((e) => e.date)).size;
  const variety = new Set(wMeals.map((m) => (m.name || "").toLowerCase().split(" + ")[0])).size;
  const tally = (arr) => {
    const liked = {}, freq = {};
    arr.forEach((e) => { const key = (e.name || "").split(" + ")[0].trim(); if (!key) return; freq[key] = (freq[key] || 0) + 1; if (e.liked) liked[key] = (liked[key] || 0) + 1; });
    const pool = Object.keys(liked).length ? liked : freq; let best = null, n = 0;
    Object.entries(pool).forEach(([k, v]) => { if (v > n) { best = k; n = v; } });
    return best ? { name: best, count: freq[best] || n } : null;
  };
  const topMeal = tally(wMeals), topWorkout = tally(wWorkouts);
  const empty = meals.length === 0 && workouts.length === 0;
  const windowEmpty = wMeals.length === 0 && wWorkouts.length === 0;

  const playRecap = async () => {
    setRecapBusy(true);
    const stats = { days: daysTracked, meals: wMeals.length, workouts: wWorkouts.length, variety, streak, top: topMeal?.name || "" };
    const fallback = {
      greeting: "Here's your week",
      stats: [{ value: stats.days, label: stats.days === 1 ? "day showing up" : "days showing up" }, { value: stats.meals, label: "meals logged" }, { value: stats.variety, label: "different dishes" }],
      lines: [stats.top ? `${stats.top} was a favourite this week.` : "You kept things gently in motion.", "Showing up is the whole thing, and you did."],
      closing: "Here's to a kind week ahead.",
    };
    try {
      const raw = await callClaude([{ role: "user", content: `Write a short, warm, gentle weekly recap for a nutrition app. No guilt, no calorie talk, focus on showing up, variety and care. Data: ${JSON.stringify(stats)}. Reply ONLY with JSON: {"greeting":"3-5 words","stats":[{"value":0,"label":"short"}],"lines":["warm sentence","warm sentence"],"closing":"short kind sign off"}. Use 2-3 stats from the data.` }]);
      const j = extractJSON(raw);
      setRecap(j && j.stats ? j : fallback);
    } catch (e) { setRecap(fallback); }
    setRecapBusy(false);
  };

  return (
    <div className="cc-enter">
      <SectionHead Icon={BarChart3} c={C.sage} title="Your insights" sub="A gentle look at how your week is shaping up" />

      {empty ? (
        <div className="cc-card" style={{ padding: 30, textAlign: "center" }}><BarChart3 size={26} color={C.muted} style={{ marginBottom: 12 }} /><p className="cc-soft" style={{ fontSize: 14, lineHeight: 1.5 }}>Log a few meals and workouts and your gentle patterns will appear here.</p></div>
      ) : (
        <>
          {/* showing-up hero */}
          <div className="cc-card" style={{ padding: 24, marginBottom: 14, textAlign: "center", position: "relative", overflow: "hidden" }}>
            <div style={{ position: "absolute", inset: 0, background: "radial-gradient(440px 220px at 50% -30%, rgba(138,165,133,0.24), transparent 70%)", pointerEvents: "none" }} />
            <div style={{ position: "relative" }}>
              <img src={SAGE_IMG} alt="Sage" style={{ width: 66, height: 66, display: "block", margin: "0 auto 8px" }} />
              <div className="cc-display" style={{ fontSize: 46, fontWeight: 600, lineHeight: 1, color: C.ink }}>{streak === 0 ? "Day one" : <CountUp to={streak} />}</div>
              <p className="cc-soft" style={{ fontSize: 14, marginTop: 9, lineHeight: 1.5, maxWidth: 280, marginLeft: "auto", marginRight: "auto" }}>{streak === 0 ? "Log a meal whenever you're ready, and your run begins." : `${streak === 1 ? "day" : "days"} showing up in a row. That's the whole thing, really.`}</p>
              <div style={{ display: "flex", justifyContent: "center", gap: 7, marginTop: 18 }}>
                {chart.map((d, i) => (
                  <div key={i} title={d.label} style={{ width: 9, height: 9, borderRadius: 999, background: d.n ? `linear-gradient(135deg,${C.sage},${C.clay})` : "rgba(120,100,80,0.16)" }} />
                ))}
              </div>
            </div>
          </div>

          <DatePill nav={insNav} verb="Week to" />

          {/* Sage's recap */}
          <button className="cc-btn" onClick={playRecap} disabled={recapBusy} style={{ width: "100%", padding: 0, marginBottom: 16, borderRadius: 20, overflow: "hidden", textAlign: "left", border: "1px solid rgba(255,255,255,0.7)", background: `linear-gradient(135deg, ${C.clay}, ${C.clayDeep})`, boxShadow: "0 14px 32px rgba(194,114,78,0.3)" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 14, padding: "15px 18px", color: "#fff" }}>
              <div style={{ width: 44, height: 44, borderRadius: 14, background: "rgba(255,255,255,0.22)", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>{recapBusy ? <Loader2 className="cc-spin" size={20} /> : <Play size={20} />}</div>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 700, fontSize: 15.5 }}>{recapBusy ? "Sage is looking back…" : `Play ${anchorToday ? "your week" : "this week"}`}</div>
                <div style={{ fontSize: 12.5, opacity: 0.92 }}>A little recap from Sage, just for you</div>
              </div>
            </div>
          </button>

          <div className="cc-stat-grid" style={{ marginBottom: 14 }}>
            <StatCard big={daysTracked} unit="of 7 days" label="This week" c={C.sage} />
            <StatCard big={wMeals.length} unit={wMeals.length === 1 ? "meal" : "meals"} label="Logged" c={C.protein} />
            <StatCard big={variety} unit="different dishes" label="Variety" c={C.clay} />
            <StatCard big={wWorkouts.length} unit={wWorkouts.length === 1 ? "session" : "sessions"} label="Movement" c={C.coral} />
          </div>

          <div className="cc-card" style={{ padding: 18, marginBottom: 14 }}>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 8, marginBottom: 16, flexWrap: "wrap" }}>
              <div className="cc-soft" style={{ fontSize: 13, fontWeight: 600 }}>{anchorToday ? "Last 7 days" : `7 days to ${dayLabelOf(anchor)}`}</div>
              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                <span style={{ display: "inline-flex", alignItems: "center", gap: 5, fontSize: 11, color: C.muted }}><span style={{ width: 9, height: 9, borderRadius: 3, background: `linear-gradient(135deg,${C.sage},${C.clay})` }} /> meals</span>
                <span style={{ display: "inline-flex", alignItems: "center", gap: 5, fontSize: 11, color: C.muted }}><span style={{ width: 7, height: 7, borderRadius: 999, background: C.coral }} /> moved</span>
              </div>
            </div>
            <div style={{ display: "flex", alignItems: "flex-end", justifyContent: "space-between", gap: 8, height: 108 }}>
              {chart.map((d, i) => (
                <div key={i} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", gap: 6, height: "100%", justifyContent: "flex-end" }}>
                  <div style={{ flex: 1, width: "100%", display: "flex", alignItems: "flex-end", justifyContent: "center" }}>
                    <div style={{ width: "100%", maxWidth: 28, height: `${(d.n / maxN) * 100}%`, minHeight: d.n ? 8 : 3, borderRadius: "8px 8px 4px 4px", background: d.n ? `linear-gradient(180deg,${C.sage},${C.clay})` : "rgba(120,100,80,0.12)", transition: "height .6s cubic-bezier(.16,1,.3,1)" }} />
                  </div>
                  <div style={{ height: 8, display: "flex", alignItems: "center", justifyContent: "center" }}>{d.mv ? <span style={{ width: 6, height: 6, borderRadius: 999, background: C.coral }} /> : null}</div>
                  <span className="cc-muted" style={{ fontSize: 11 }}>{d.label}</span>
                </div>
              ))}
            </div>
            <p className="cc-soft" style={{ fontSize: 12.5, lineHeight: 1.5, marginTop: 14, textAlign: "center" }}>{daysWithMeals === 0 ? "Nothing logged in this stretch yet." : `You logged on ${daysWithMeals} of 7 days${daysWithMove ? ` and moved on ${daysWithMove}` : ""}.`}</p>
          </div>

          {windowEmpty ? (
            <div className="cc-card" style={{ padding: 22, textAlign: "center" }}>
              <p className="cc-soft" style={{ fontSize: 13.5, lineHeight: 1.5 }}>Nothing logged in this stretch. Pick another week, or this one's just waiting for you.</p>
            </div>
          ) : (
            <div className="cc-stat-grid">
              <FaveCard title="Most-loved meal" Icon={Utensils} c={C.clay} item={topMeal} />
              <FaveCard title="Go-to movement" Icon={Dumbbell} c={C.coral} item={topWorkout} />
            </div>
          )}
        </>
      )}

      {recap && <RecapOverlay recap={recap} onClose={() => setRecap(null)} />}
    </div>
  );
}

function StatCard({ big, unit, label, c }) {
  return (<div className="cc-card" style={{ padding: 16 }}><div className="cc-tag" style={{ color: c, fontSize: 10, marginBottom: 6 }}>{label}</div><div className="cc-display" style={{ fontSize: 30, fontWeight: 600, lineHeight: 1, color: C.ink }}><CountUp to={big} dur={900} /></div><div className="cc-soft" style={{ fontSize: 12.5, marginTop: 3 }}>{unit}</div></div>);
}
function FaveCard({ title, Icon, c, item }) {
  return (<div className="cc-card" style={{ padding: 16 }}><div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10 }}><Icon size={16} color={c} /><span className="cc-soft" style={{ fontSize: 12.5, fontWeight: 600 }}>{title}</span></div>{item ? (<><div style={{ fontWeight: 700, fontSize: 16 }}>{item.name}</div><div className="cc-muted" style={{ fontSize: 12.5, marginTop: 2 }}>logged {item.count} {item.count === 1 ? "time" : "times"}</div></>) : (<div className="cc-muted" style={{ fontSize: 13 }}>Not enough yet</div>)}</div>);
}

function CountUp({ to, dur = 1000 }) {
  const [n, setN] = useState(0);
  useEffect(() => {
    let raf, start;
    const tick = (t) => { if (!start) start = t; const p = Math.min(1, (t - start) / dur); setN(Math.round(to * (1 - Math.pow(1 - p, 3)))); if (p < 1) raf = requestAnimationFrame(tick); };
    raf = requestAnimationFrame(tick); return () => cancelAnimationFrame(raf);
  }, [to, dur]);
  return <>{n}</>;
}

function RecapOverlay({ recap, onClose }) {
  const dots = Array.from({ length: 14 });
  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 80, display: "flex", alignItems: "center", justifyContent: "center", overflow: "hidden" }}>
      <div style={{ position: "absolute", inset: 0, animation: "kenburns 16s ease-out both",
        background: "radial-gradient(900px 600px at 20% 10%, rgba(196,178,224,0.6), transparent 60%), radial-gradient(800px 600px at 85% 20%, rgba(176,214,202,0.55), transparent 60%), radial-gradient(900px 700px at 50% 110%, rgba(236,196,182,0.7), transparent 60%), linear-gradient(180deg,#F6F0E5,#EFE6D7)" }} />
      {dots.map((_, i) => (
        <span key={i} style={{ position: "absolute", bottom: -20, left: `${(i * 7 + 5) % 100}%`, width: 8 + (i % 3) * 4, height: 8 + (i % 3) * 4, borderRadius: 999, background: [C.protein, C.sage, C.apricot, C.clay][i % 4], opacity: 0.5, animation: `driftUp ${7 + (i % 5)}s linear ${i * 0.4}s infinite` }} />
      ))}

      <div className="cc-layer" style={{ width: "100%", maxWidth: 460, margin: 18, textAlign: "center", padding: "0 8px" }}>
        <button className="cc-btn" onClick={onClose} style={{ position: "absolute", top: 18, right: 18, width: 40, height: 40, borderRadius: 14, background: "rgba(255,255,255,0.7)", border: "1px solid rgba(255,255,255,0.8)", display: "flex", alignItems: "center", justifyContent: "center" }}><X size={18} color={C.ink} /></button>

        <div className="cc-beat" style={{ animationDelay: "0.1s" }}>
          <span className="cc-tag" style={{ color: C.clay }}>This week</span>
          <h1 className="cc-display" style={{ fontSize: 40, fontWeight: 600, marginTop: 8, lineHeight: 1.05 }}>{recap.greeting}</h1>
        </div>

        <div style={{ display: "flex", justifyContent: "center", gap: 12, margin: "28px 0", flexWrap: "wrap" }}>
          {(recap.stats || []).slice(0, 3).map((s, i) => (
            <div key={i} className="cc-beat cc-card" style={{ animationDelay: `${0.5 + i * 0.45}s`, padding: "18px 16px", minWidth: 96, background: "rgba(255,255,255,0.6)" }}>
              <div className="cc-display" style={{ fontSize: 38, fontWeight: 600, color: [C.clay, C.sage, C.apricot][i % 3], lineHeight: 1 }}><CountUp to={Number(s.value) || 0} dur={1100} /></div>
              <div className="cc-soft" style={{ fontSize: 12, marginTop: 6, lineHeight: 1.3 }}>{s.label}</div>
            </div>
          ))}
        </div>

        <div style={{ display: "flex", flexDirection: "column", gap: 12, marginBottom: 26 }}>
          {(recap.lines || []).map((line, i) => (
            <p key={i} className="cc-beat cc-display" style={{ animationDelay: `${1.9 + i * 0.5}s`, fontSize: 19, fontWeight: 400, lineHeight: 1.4, color: C.ink, padding: "0 10px" }}>{line}</p>
          ))}
        </div>

        <div className="cc-beat" style={{ animationDelay: `${2.4 + (recap.lines || []).length * 0.5}s` }}>
          <p className="cc-soft" style={{ fontSize: 14, marginBottom: 16 }}>{recap.closing}</p>
          <button className="cc-btn cc-primary" onClick={onClose} style={{ padding: "13px 28px", fontSize: 15 }}>Lovely, thanks</button>
        </div>
      </div>
    </div>
  );
}

/* ================================================================== */
/*  Shared                                                             */
/* ================================================================== */
function SectionHead({ Icon, c, title, sub }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 13, marginBottom: 18, paddingTop: 6 }}>
      <div style={{ width: 44, height: 44, borderRadius: 14, background: `${c}22`, border: `1px solid ${c}33`, display: "flex", alignItems: "center", justifyContent: "center" }}><Icon size={21} color={c} /></div>
      <div><h2 className="cc-display" style={{ fontSize: 22, fontWeight: 600, letterSpacing: "-0.01em" }}>{title}</h2><p className="cc-soft" style={{ fontSize: 13 }}>{sub}</p></div>
    </div>
  );
}

function DatePicker({ value, minKey, maxKey, onPick, onClose }) {
  const toDate = (k) => { const [Y, M, D] = k.split("-").map(Number); return new Date(Y, M - 1, D); };
  const sel = value ? toDate(value) : new Date();
  const [vm, setVm] = useState(new Date(sel.getFullYear(), sel.getMonth(), 1));
  const today = todayKey();
  const max = maxKey || today;
  const min = minKey || null;

  const monthLabel = vm.toLocaleDateString("en-GB", { month: "long", year: "numeric" });
  const firstDow = vm.getDay();
  const daysInMonth = new Date(vm.getFullYear(), vm.getMonth() + 1, 0).getDate();
  const cells = [];
  for (let i = 0; i < firstDow; i++) cells.push(null);
  for (let d = 1; d <= daysInMonth; d++) cells.push(d);
  const keyFor = (d) => keyOf(new Date(vm.getFullYear(), vm.getMonth(), d));
  const blocked = (k) => (min && k < min) || k > max;
  const canPrev = !min || keyOf(new Date(vm.getFullYear(), vm.getMonth(), 0)) >= min;
  const canNext = keyOf(new Date(vm.getFullYear(), vm.getMonth() + 1, 1)) <= max;
  const mbtn = (on, fn, dir) => (
    <button className="cc-btn" disabled={!on} onClick={fn} aria-label={dir === "l" ? "Previous month" : "Next month"}
      style={{ width: 30, height: 30, borderRadius: 9, display: "flex", alignItems: "center", justifyContent: "center", background: on ? "rgba(255,255,255,0.6)" : "transparent", border: "1px solid rgba(255,255,255,0.7)", opacity: on ? 1 : 0.3, cursor: on ? "pointer" : "default" }}>
      {dir === "l" ? <ChevronLeft size={15} color={C.clayDeep} /> : <ChevronRight size={15} color={C.clayDeep} />}
    </button>
  );

  return (
    <>
      <div onClick={onClose} style={{ position: "fixed", inset: 0, zIndex: 60, background: "rgba(59,52,43,0.28)", backdropFilter: "blur(2px)" }} />
      <div className="cc-pop" style={{ position: "fixed", top: "50%", left: "50%", transform: "translate(-50%,-50%)", zIndex: 61, width: 300, maxWidth: "calc(100vw - 36px)", background: "rgba(255,255,255,0.98)", backdropFilter: "blur(18px)", border: "1px solid rgba(255,255,255,0.85)", borderRadius: 20, padding: 16, boxShadow: "0 24px 60px rgba(120,98,74,0.3)" }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 12 }}>
          <span className="cc-tag cc-soft">Jump to a date</span>
          <button className="cc-btn" onClick={onClose} aria-label="Close" style={{ background: "transparent", padding: 4, display: "flex", color: C.muted }}><X size={16} /></button>
        </div>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 10 }}>
          {mbtn(canPrev, () => setVm(new Date(vm.getFullYear(), vm.getMonth() - 1, 1)), "l")}
          <span style={{ fontWeight: 700, fontSize: 14, color: C.ink }}>{monthLabel}</span>
          {mbtn(canNext, () => setVm(new Date(vm.getFullYear(), vm.getMonth() + 1, 1)), "r")}
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 2, marginBottom: 4 }}>
          {["S", "M", "T", "W", "T", "F", "S"].map((d, i) => (
            <div key={i} style={{ textAlign: "center", fontSize: 10.5, fontWeight: 700, color: C.muted, padding: "2px 0" }}>{d}</div>
          ))}
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 2 }}>
          {cells.map((d, i) => {
            if (d === null) return <div key={i} />;
            const k = keyFor(d); const dis = blocked(k); const isSel = k === value; const isToday = k === today;
            return (
              <button key={i} className="cc-btn" disabled={dis} onClick={() => { onPick(k); onClose(); }}
                style={{ height: 34, borderRadius: 9, fontSize: 12.5, fontWeight: isSel ? 700 : 500,
                  background: isSel ? `linear-gradient(135deg,${C.clay},${C.clayDeep})` : "transparent",
                  color: dis ? "rgba(120,100,80,0.28)" : isSel ? "#fff" : C.ink,
                  border: isToday && !isSel ? `1px solid ${C.clay}66` : "1px solid transparent",
                  cursor: dis ? "default" : "pointer" }}>
                {d}
              </button>
            );
          })}
        </div>
      </div>
    </>
  );
}

function DatePill({ nav, verb = "Logging to", hint = false }) {
  const [open, setOpen] = useState(false);
  if (!nav) return null;
  const { dayLabel, viewingToday, canBack, canFwd, onPrev, onNext, onToday, value, minKey, maxKey, onPick } = nav;
  const chipBg = viewingToday ? "rgba(255,255,255,0.6)" : "rgba(213,138,102,0.16)";
  const chipBorder = viewingToday ? "rgba(255,255,255,0.72)" : `${C.clay}44`;
  const chev = (dir, on, fn) => (
    <button className="cc-btn" onClick={fn} disabled={!on} aria-label={dir === "l" ? "Previous day" : "Next day"}
      style={{ width: 32, height: 32, borderRadius: 10, display: "flex", alignItems: "center", justifyContent: "center", background: on ? "rgba(255,255,255,0.6)" : "transparent", border: "1px solid rgba(255,255,255,0.7)", opacity: on ? 1 : 0.3, cursor: on ? "pointer" : "default" }}>
      {dir === "l" ? <ChevronLeft size={16} color={C.clayDeep} /> : <ChevronRight size={16} color={C.clayDeep} />}
    </button>
  );
  return (
    <div style={{ marginBottom: 16, marginTop: -4 }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
        {chev("l", canBack, onPrev)}
        <div style={{ position: "relative" }}>
          <button className="cc-btn" onClick={() => setOpen((o) => !o)} aria-label="Pick a date"
            style={{ display: "inline-flex", alignItems: "center", gap: 7, padding: "6px 13px", borderRadius: 999, background: chipBg, border: `1px solid ${chipBorder}`, color: C.ink, fontSize: 12.5, fontWeight: 600 }}>
            <CalendarDays size={13} color={C.clay} /> {verb} {dayLabel}
          </button>
          {open && <DatePicker value={value} minKey={minKey} maxKey={maxKey} onPick={onPick} onClose={() => setOpen(false)} />}
        </div>
        {chev("r", canFwd, onNext)}
        {!viewingToday && (
          <button className="cc-btn" onClick={onToday} style={{ display: "inline-flex", alignItems: "center", gap: 5, padding: "5px 11px", borderRadius: 999, background: "transparent", border: `1px solid ${C.clay}33`, color: C.clayDeep, fontSize: 11.5, fontWeight: 600 }}>
            <RotateCcw size={11} color={C.clay} /> Today
          </button>
        )}
      </div>
      {hint && viewingToday && <div className="cc-muted" style={{ fontSize: 11, marginTop: 6, paddingLeft: 2 }}>Tap the date to log to another day</div>}
    </div>
  );
}
